const src = $input.first().json;
const b = src.body && typeof src.body === 'object' ? src.body : src;
const projectId = String(b.project_id || src.project_id || '').trim();
const allowed = ['status_update', 'feasibility_sent', 'floor_plan_sent'];
const rawType = String(b.update_type || b.communication_type || src.update_type || 'status_update').trim();
const commType = allowed.indexOf(rawType) !== -1 ? rawType : 'status_update';
const defaultSubjects = { status_update: 'Project status update', feasibility_sent: 'Feasibility study shared', floor_plan_sent: 'Floor plans shared' };
const subject = String(b.subject || src.subject || defaultSubjects[commType]);
const message = String(b.message || src.message || 'Update logged via DD-3 Communication Logger.');
const sentBy = String(b.sent_by_email || src.sent_by_email || 'n8n@workflow.internal').trim();
return [{ json: { project_id: projectId, communication_type: commType, subject: subject, message: message, sent_by_email: sentBy, sent_to_owner: false, metadata: { source: 'dd3-communication-logger', original_update_type: rawType, logged_at: new Date().toISOString() } } }];
